class StoryCombinedFiltersComponent {
  allRows = [
    { product: 'Laptop Pro', category: 'Electronica', status: 'Disponible', price: 1299.99 },
    { product: 'Monitor 27"', category: 'Electronica', status: 'Disponible', price: 449.00 },
